// Reads the warm cache file written by the nightly job (not the live db).
import { readFileSync } from 'node:fs';
export const readWarmUser = (id) => {
  const rows = JSON.parse(readFileSync('warm-cache.json', 'utf8'));
  return rows[id] ?? null;
};

